const ALL_IDS=new Set(INSTRUMENTS.map(function(n){return n.id;}));
const buildRahmen = function(){
  const combined=EXPLICIT.concat(IMPLICIT);
  const ex=new Set(combined.map(function([s,t]){return Math.min(s,t)+"-"+Math.max(s,t);}));
  const r=[];
  Object.entries(RAHMEN_TARGETS).forEach(function([rid,ts]){
    const rv=Number(rid);
    ts.forEach(function(t){
      if(!ALL_IDS.has(rv)||!ALL_IDS.has(t))return;
      const k=Math.min(rv,t)+"-"+Math.max(rv,t);
      if(!ex.has(k))r.push([rv,t]);
    });
  });
  return r;
};
const RAHMEN_LINKS=buildRahmen();
const ALL_LINKS=
  EXPLICIT.filter(function(p){return ALL_IDS.has(p[0])&&ALL_IDS.has(p[1]);})
    .map(function(p){return {s:p[0],t:p[1],type:"explicit"};})
  .concat(
    IMPLICIT.filter(function(p){return ALL_IDS.has(p[0])&&ALL_IDS.has(p[1]);})
      .map(function(p){return {s:p[0],t:p[1],type:"implicit"};})
  ).concat(
    RAHMEN_LINKS.map(function(p){return {s:p[0],t:p[1],type:"rahmen"};})
  );

const getZone = function(inst){if(inst.cat==="RAHMEN")return"RAHMEN";return ZONE_OVERRIDE[inst.id]||CAT_GROUP[inst.cat]||"SK";};
const getColor = function(inst){if(inst.cat==="RAHMEN")return COL.RAHMEN;return COL[getZone(inst)]||COL.SK;};
const fibSpread = function(i,n,r,cx){
  const phi=Math.acos(1-2*(i+0.5)/n);
  const theta=Math.PI*(1+Math.sqrt(5))*i;
  return new THREE.Vector3(
    cx.x+r*Math.sin(phi)*Math.cos(theta),
    cx.y+r*Math.sin(phi)*Math.sin(theta)*0.5,
    cx.z+r*Math.cos(phi)*0.38
  );
};


function MultiverseView({ onBack }){
  const canvasRef=useRef(null);
  const stateRef=useRef({selected:null,search:""});
  const worldPos=useRef({});
  const meshById=useRef({});
  const allLineMeshes=useRef([]);
  const [selected,setSelected]=useState(null);
  const [search,setSearch]=useState("");
  const [searchFocus,setSearchFocus]=useState(false);
  const [tooltip,setTooltip]=useState(null);
  const searchInputRef=useRef(null);
  const labelContainerRef=useRef(null);
  const labelEls=useRef({});   // id → DOM div

  useEffect(()=>{stateRef.current.selected=selected;},[selected]);
  useEffect(()=>{stateRef.current.search=search;},[search]);

  useEffect(()=>{
    const canvas=canvasRef.current;
    const renderer=new THREE.WebGLRenderer({canvas,antialias:true});
    renderer.setPixelRatio(Math.min(window.devicePixelRatio,2));
    renderer.setClearColor(0x0f172a,1);

    const scene=new THREE.Scene();
    const camera=new THREE.PerspectiveCamera(44,1,0.1,100);


    scene.add(new THREE.AmbientLight(0xffffff,0.65));
    const sun=new THREE.DirectionalLight(0xffffff,0.85);
    sun.position.set(5,8,6);scene.add(sun);

    // Wrap entire world in one group so it all spins together
    // One group — everything rotates together
    const sceneGroup=new THREE.Group();
    scene.add(sceneGroup);

    // Venn spheres
    Object.entries(VCENTER).forEach(([key,center])=>{
      const col=COL[key].hex;
      // Soft glowing sphere — dense but fully transparent (no lines)
      const fillBack=new THREE.Mesh(new THREE.SphereGeometry(SR*1.05,32,32),new THREE.MeshBasicMaterial({color:col,transparent:true,opacity:0.06,side:THREE.BackSide,depthWrite:false}));
      fillBack.position.copy(center);sceneGroup.add(fillBack);
      const fillFront=new THREE.Mesh(new THREE.SphereGeometry(SR,32,32),new THREE.MeshPhongMaterial({color:col,emissive:col,emissiveIntensity:0.08,transparent:true,opacity:0.13,side:THREE.FrontSide,depthWrite:false}));
      fillFront.position.copy(center);sceneGroup.add(fillFront);
    });

    // Torus is a static track — very faint
    const torus=new THREE.Mesh(new THREE.TorusGeometry(RAHMEN_R,0.02,8,90),new THREE.MeshBasicMaterial({color:0xfbbf24,transparent:true,opacity:0.12}));
    torus.rotation.x=Math.PI*0.18;sceneGroup.add(torus);

    // Place nodes
    const byZone={};
    INSTRUMENTS.forEach(inst=>{
      if(inst.cat==="RAHMEN")return;
      const z=getZone(inst);
      if(!byZone[z])byZone[z]=[];
      byZone[z].push(inst);
    });
    // Desired max spread per zone — will be clamped to stay inside sphere
    const spreadR={ALL:0.45,SK_GS:0.75,SK_UF:0.75,GS_UF:0.75,SK:2.5,GS:2.5,UF:2.2};

    // Sphere centre for each zone (for clamping)
    const zoneSphere={SK:"SK",GS:"GS",UF:"UF",
      SK_GS:"SK",SK_UF:"SK",GS_UF:"GS",ALL:"SK"};
    const vcArr={SK:[-1.8,1.0],GS:[1.8,1.0],UF:[0,-1.8]};
    const SR_VAL=3.2, MARGIN=0.15;

    // Precompute degree per instrument for gravity weighting
    const instDeg={};
    ALL_LINKS.forEach(function(lk){
      instDeg[lk.s]=(instDeg[lk.s]||0)+1;
      instDeg[lk.t]=(instDeg[lk.t]||0)+1;
    });

    Object.entries(byZone).forEach(([zone,insts])=>{
      const cx=ZONE_CENTER[zone]||ZONE_CENTER.SK;
      const desiredMaxR=spreadR[zone]||1.5;

      // Compute max allowed r so all nodes stay inside sphere
      const sphKey=zoneSphere[zone]||"SK";
      const vc=vcArr[sphKey];
      const dx=cx.x-vc[0], dy=cx.y-vc[1];
      const distCxVc=Math.sqrt(dx*dx+dy*dy);
      const rCap=SR_VAL-MARGIN-distCxVc;
      const maxR=Math.min(desiredMaxR, rCap);

      // Sort by degree descending so highly connected get index 0 (centre of fib)
      const sorted=insts.slice().sort(function(a,b){
        return (instDeg[b.id]||0)-(instDeg[a.id]||0);
      });

      const maxDeg=instDeg[sorted[0].id]||1;
      const minDeg=instDeg[sorted[sorted.length-1].id]||0;
      const degRange=Math.max(maxDeg-minDeg,1);

      // Step 1: initial positions + compute node radii
      var zonePosArr=[];
      sorted.forEach(function(inst,i){
        const normDeg=((instDeg[inst.id]||0)-minDeg)/degRange;
        // Strong 3D spread: floor 0.55 so even hub nodes stay away from centre
        const rScale=0.55+(1-normDeg)*0.45;
        const r=maxR*rScale;
        const pos=fibSpread(i,sorted.length,r,cx);
        const dg=instDeg[inst.id]||0;
        const nr=0.08+Math.sqrt(dg)*0.038;
        zonePosArr.push({inst:inst,pos:pos.clone(),nr:nr});
      });

      // Step 2: repulsion pass — push overlapping nodes apart (10 iterations)
      for(var iter=0;iter<20;iter++){
        for(var a=0;a<zonePosArr.length;a++){
          for(var b=a+1;b<zonePosArr.length;b++){
            var pa=zonePosArr[a], pb=zonePosArr[b];
            var minDist=pa.nr+pb.nr+0.12; // sum of radii + generous gap
            var rx=pb.pos.x-pa.pos.x;
            var ry=pb.pos.y-pa.pos.y;
            var rz=pb.pos.z-pa.pos.z;
            var dist=Math.sqrt(rx*rx+ry*ry+rz*rz)||0.001;
            if(dist<minDist){
              var push=(minDist-dist)*0.6;
              var nx=rx/dist, ny=ry/dist, nz=rz/dist;
              pa.pos.x-=nx*push; pa.pos.y-=ny*push; pa.pos.z-=nz*push;
              pb.pos.x+=nx*push; pb.pos.y+=ny*push; pb.pos.z+=nz*push;
            }
          }
        }
      }

      // Step 3: clamp back inside sphere and create meshes
      var isInter=zone.includes("_")||zone==="ALL";
      zonePosArr.forEach(function(item){
        var inst=item.inst, pos=item.pos, nr=item.nr;
        // Clamp: dist from sphere centre (VCENTER) must stay inside SR
        var sphC=VCENTER[zoneSphere[zone]||"SK"];
        var ddx=pos.x-sphC.x, ddy=pos.y-sphC.y, ddz=pos.z-sphC.z;
        var dd=Math.sqrt(ddx*ddx+ddy*ddy+ddz*ddz);
        var limit=SR_VAL-nr-0.1;
        if(dd>limit){
          var sc=limit/dd;
          pos.x=sphC.x+ddx*sc; pos.y=sphC.y+ddy*sc; pos.z=sphC.z+ddz*sc;
        }
        worldPos.current[inst.id]=pos.clone();
        const em=isInter?0.65:0.38;
        const col=getColor(inst).hex;
        const mat=new THREE.MeshPhongMaterial({color:col,emissive:col,emissiveIntensity:em});
        const mesh=new THREE.Mesh(new THREE.SphereGeometry(nr,10,10),mat);
        mesh.position.copy(pos);
        mesh.userData={id:inst.id,inst:inst,baseR:nr,baseEm:em};
        sceneGroup.add(mesh);
        meshById.current[inst.id]=mesh;
      });
    });

    // Rahmen nodes on ring
    const rahmenInsts=INSTRUMENTS.filter(n=>n.cat==="RAHMEN");
    const tiltX=Math.PI*0.18;
    const rahmenTrack=[];

    rahmenInsts.forEach(function(inst,i){
      const angle=(i/rahmenInsts.length)*Math.PI*2;
      const pos=new THREE.Vector3(
        RAHMEN_R*Math.cos(angle),
        RAHMEN_R*Math.sin(angle)*Math.cos(tiltX),
        RAHMEN_R*Math.sin(angle)*Math.sin(tiltX)
      );
      worldPos.current[inst.id]=pos.clone();
      const mat=new THREE.MeshPhongMaterial({color:0xfbbf24,emissive:0xfbbf24,emissiveIntensity:0.65});
      const mesh=new THREE.Mesh(new THREE.SphereGeometry(0.2,10,10),mat);
      mesh.position.copy(pos);
      mesh.userData={id:inst.id,inst,baseR:0.2,baseEm:0.65};
      sceneGroup.add(mesh);
      meshById.current[inst.id]=mesh;
      rahmenTrack.push({mesh:mesh,baseAngle:angle});
    });

    // ── Draw ALL lines upfront ──
    const mkLine=(posA,posB,col,op,dash)=>{
      const pts=[posA.clone(),posB.clone()];
      const geo=new THREE.BufferGeometry().setFromPoints(pts);
      const mat=dash
        ?new THREE.LineDashedMaterial({color:col,transparent:true,opacity:op,dashSize:0.28,gapSize:0.18})
        :new THREE.LineBasicMaterial({color:col,transparent:true,opacity:op});
      const line=new THREE.Line(geo,mat);
      if(dash)line.computeLineDistances();
      return line;
    };

    allLineMeshes.current=[];
    ALL_LINKS.forEach(({s,t,type})=>{
      const posS=worldPos.current[s];
      const posT=worldPos.current[t];
      if(!posS||!posT)return;
      const isE=type==="explicit",isI=type==="implicit";
      const col=isE?0x93c5fd:isI?0xc4b5fd:0xfcd34d;
      const op=isE?0.18:isI?0.12:0.08;
      const dash=!isE;
      const line=mkLine(posS,posT,col,op,dash);
      sceneGroup.add(line);
      allLineMeshes.current.push({line,s,t,type,baseOp:op});
    });

    // ── Create HTML label elements ──
    const container = labelContainerRef.current;
    const _labelEls = {};
    if (container) {
      INSTRUMENTS.forEach(inst => {
        const div = document.createElement("div");
        div.style.cssText = [
          "position:absolute","pointer-events:none","transform:translate(-50%,-100%)",
          "white-space:nowrap","font-family:system-ui,sans-serif",
          "font-size:9px","font-weight:600","letter-spacing:0.04em",
          "padding:2px 7px","border-radius:5px","opacity:0",
          "transition:opacity 0.4s ease","will-change:opacity,transform",
          "background:rgba(15,23,42,0.82)","border:1px solid rgba(255,255,255,0.12)",
          "color:"+getColor(inst).css,
          "text-shadow:none","backdrop-filter:blur(4px)",
          "margin-bottom:4px",
        ].join(";");
        div.textContent = RAHMEN_IDS.has(inst.id) ? (RAHMEN_LABELS[inst.id]||inst.name) : inst.name;
        div.dataset.id = inst.id;
        container.appendChild(div);
        _labelEls[inst.id] = div;
      });
      labelEls.current = _labelEls;
    }

    // Raycaster + orbit
    const raycaster=new THREE.Raycaster();
    raycaster.params.Points={threshold:0.1};
    const mouse=new THREE.Vector2();
    let theta=0.18, phi=Math.PI*0.32;
    let isDragging=false, prevX=0, prevY=0, autoRot=true;
    const ORBITR=16;
    const setCamera=()=>{
      camera.position.set(
        ORBITR*Math.sin(phi)*Math.sin(theta),
        ORBITR*Math.cos(phi),
        ORBITR*Math.sin(phi)*Math.cos(theta)
      );
      camera.lookAt(0,0,0);
    };
    setCamera();

    const allMeshes=Object.values(meshById.current);

    const onDown=e=>{isDragging=true;autoRot=false;prevX=e.clientX;prevY=e.clientY;};
    const onUp=()=>{isDragging=false;setTimeout(()=>{autoRot=true;},4000);};
    const onMove=e=>{
      if(isDragging){
        theta-=(e.clientX-prevX)*0.012;
        phi-=(e.clientY-prevY)*0.012;
        phi=Math.max(0.06,Math.min(Math.PI-0.06,phi));
        prevX=e.clientX;prevY=e.clientY;setCamera();return;
      }
      const rect=canvas.getBoundingClientRect();
      mouse.set(((e.clientX-rect.left)/rect.width)*2-1,-((e.clientY-rect.top)/rect.height)*2+1);
      raycaster.setFromCamera(mouse,camera);
      const hits=raycaster.intersectObjects(allMeshes);
      if(hits.length){
        const inst=hits[0].object.userData.inst;
        const wp=hits[0].object.getWorldPosition(new THREE.Vector3()).project(camera);
        setTooltip({inst,x:(wp.x*0.5+0.5)*rect.width+rect.left,y:(-wp.y*0.5+0.5)*rect.height+rect.top});
        canvas.style.cursor="pointer";
      }else{setTooltip(null);canvas.style.cursor="default";}
    };
    const onClick=e=>{
      if(isDragging)return;
      const rect=canvas.getBoundingClientRect();
      mouse.set(((e.clientX-rect.left)/rect.width)*2-1,-((e.clientY-rect.top)/rect.height)*2+1);
      raycaster.setFromCamera(mouse,camera);
      const hits=raycaster.intersectObjects(allMeshes);
      if(hits.length){const id=hits[0].object.userData.id;setSelected(p=>p===id?null:id);}
      else setSelected(null);
    };

    canvas.addEventListener("mousedown",onDown);
    window.addEventListener("mouseup",onUp);
    canvas.addEventListener("mousemove",onMove);
    canvas.addEventListener("click",onClick);

    const resize=()=>{
      const w=(canvas.parentElement?canvas.parentElement.clientWidth:0)||canvas.offsetWidth||800;
      const h=(canvas.parentElement?canvas.parentElement.clientHeight:0)||canvas.offsetHeight||600;
      if(w>0&&h>0){renderer.setSize(w,h,false);camera.aspect=w/h;camera.updateProjectionMatrix();}
    };
    const ro=new ResizeObserver(resize);ro.observe(canvas);
    // Call immediately to set correct size before first frame
    resize();

    let raf;
    const animate=()=>{
      raf=requestAnimationFrame(animate);
      // Rotate everything as one unit — rahmen orbits with all inner instruments
      if(autoRot){sceneGroup.rotation.y+=0.004;}


      const sel=stateRef.current.selected;
      const q=stateRef.current.search.trim().toLowerCase();

      // connected set
      const connSet=new Set();
      if(sel){ALL_LINKS.forEach(({s,t})=>{if(s===sel||t===sel){connSet.add(s);connSet.add(t);}});}

      // update node visuals
      allMeshes.forEach(m=>{
        const {id,baseR,baseEm}=m.userData;
        const isSel=id===sel,isConn=connSet.has(id);
        const isMatch=q?m.userData.inst.name.toLowerCase().includes(q):false;
        const fade=(sel&&!isSel&&!isConn)||(q&&!isMatch);
        const ts=isSel?2.5:isConn?1.7:isMatch?1.9:1;
        m.scale.lerp(new THREE.Vector3(ts,ts,ts),0.14);
        m.material.emissiveIntensity+=(((isSel?1:isConn?0.8:isMatch?0.85:baseEm))-m.material.emissiveIntensity)*0.14;
        const to=fade?0.07:1;
        if(!m.material.transparent&&to<0.99)m.material.transparent=true;
        m.material.opacity+=(to-m.material.opacity)*0.12;
      });

      // update line visuals + geometry for moving rahmen endpoints
      allLineMeshes.current.forEach(function(item){
        var line=item.line,s=item.s,t=item.t,type=item.type,baseOp=item.baseOp;
        var isE=type==="explicit",isI=type==="implicit";
        var activeOp=isE?0.9:isI?0.75:0.6;
        var op=baseOp;
        if(sel){op=(s===sel||t===sel)?activeOp:0.02;}
        else if(q){
          var sInst=INSTRUMENTS.find(function(n){return n.id===s;});
          var tInst=INSTRUMENTS.find(function(n){return n.id===t;});
          var sN=(sInst&&sInst.name)?sInst.name.toLowerCase():"";
          var tN=(tInst&&tInst.name)?tInst.name.toLowerCase():"";
          op=(sN.includes(q)||tN.includes(q))?activeOp*0.8:0.015;
        }
        line.material.opacity+=(op-line.material.opacity)*0.13;

      });

      // ── Update HTML labels ──
      if (labelContainerRef.current && Object.keys(labelEls.current).length > 0) {
        const rect = canvas.getBoundingClientRect();
        const W = rect.width, H = rect.height;

        // Compute screen position + camera distance for each node
        const nodeScreenData = [];
        const _v = new THREE.Vector3();
        Object.values(meshById.current).forEach(m => {
          if (!m.userData||!m.userData.id) return;
          m.getWorldPosition(_v);
          const dist = camera.position.distanceTo(_v);
          const proj = _v.clone().project(camera);
          const sx = (proj.x * 0.5 + 0.5) * W;
          const sy = (-proj.y * 0.5 + 0.5) * H;
          // Only label if in front of camera
          const inFront = proj.z < 1.0;
          nodeScreenData.push({ id: m.userData.id, inst: m.userData.inst, sx, sy, dist, inFront });
        });

        // Find 5 nearest (not anchor, not rahmen, in front)
        const nearestFive = nodeScreenData
          .filter(d => d.inFront && !ANCHOR_IDS.has(d.id))
          .sort((a,b) => a.dist - b.dist)
          .slice(0, 5)
          .map(d => d.id);
        const nearSet = new Set(nearestFive);

        nodeScreenData.forEach(({ id, sx, sy, dist, inFront }) => {
          const el = labelEls.current[id];
          if (!el) return;
          const isAnchor = ANCHOR_IDS.has(id);
          const isNear = nearSet.has(id);
          const isSel = sel && id === sel;
          const isConn = connSet.has(id);

          // Determine if label should be visible
          let targetOp = 0;
          if (!inFront) { targetOp = 0; }
          else if (isSel || isConn) { targetOp = 1; }
          else if (sel) { targetOp = 0; } // hide others when something selected
          else if (isAnchor) { targetOp = 0.85; }
          else if (isNear) { targetOp = 0.7; }

          // If searching, only show matches
          if (q && !isSel && !isConn) {
            var _inst=INSTRUMENTS.find(function(n){return n.id===id;}); var name=(_inst&&_inst.name)?_inst.name.toLowerCase():"";
            targetOp = name.includes(q) ? 0.9 : 0;
          }

          // Position
          el.style.left = sx + "px";
          el.style.top  = (sy - 4) + "px";
          el.style.opacity = targetOp;

          // Scale up anchors and selected
          const sc = isSel ? 1.2 : isAnchor ? 1.0 : 0.88;
          el.style.fontSize = (sc * 9) + "px";
          el.style.zIndex = isSel ? "10" : isConn ? "9" : isAnchor ? "5" : "3";
        });
      }

      renderer.render(scene,camera);
    };
    animate();

    return()=>{
      cancelAnimationFrame(raf);ro.disconnect();renderer.dispose();
      // Remove label DOM elements
      if (labelContainerRef.current) labelContainerRef.current.innerHTML = "";
      labelEls.current = {};
      canvas.removeEventListener("mousedown",onDown);
      window.removeEventListener("mouseup",onUp);
      canvas.removeEventListener("mousemove",onMove);
      canvas.removeEventListener("click",onClick);
    };
  },[]);

  const selInst=selected?INSTRUMENTS.find(n=>n.id===selected):null;
  const panelLinks=selected?{
    explicit:[],implicit:[],rahmen:[]
  }:null;
  if(selected&&panelLinks){
    const seen=new Set();
    ALL_LINKS.forEach(({s,t,type})=>{
      const other=s===selected?t:t===selected?s:null;
      if(other===null)return;
      const k=type+"-"+other;
      if(seen.has(k))return;seen.add(k);
      const inst=INSTRUMENTS.find(n=>n.id===other);
      if(inst)panelLinks[type].push({inst,dir:s===selected?"→":"←"});
    });
  }

  const searchQ=search.trim().toLowerCase();
  const searchHits=searchQ?INSTRUMENTS.filter(function(n){
    return n.name.toLowerCase().includes(searchQ)||
      n.cat.toLowerCase().includes(searchQ)||
      (RAHMEN_LABELS[n.id]||"").toLowerCase().includes(searchQ)||
      String(n.id)===searchQ;
  }).slice(0,8):[];

  const typeConf=[
    {key:"explicit",label:"Explizit",color:"#93c5fd",dash:null},
    {key:"implicit",label:"Implizit",color:"#c4b5fd",dash:"4,3"},
    {key:"rahmen",  label:"Rahmen",  color:"#fcd34d",dash:"2,4"},
  ];

  const hovInst=tooltip?tooltip.inst:null;

  return(
    <div style={{width:"100%",height:"100vh",background:"#0f172a",display:"flex",flexDirection:"column",fontFamily:"'DM Sans',system-ui,sans-serif",overflow:"hidden",color:"#e2e8f0"}}>
      <style>{"@keyframes si{from{transform:translateX(12px);opacity:0}to{transform:translateX(0);opacity:1}}"}</style>

      {/* Header */}
      <div style={{padding:"8px 16px",borderBottom:"1px solid #1e293b",display:"flex",alignItems:"center",gap:12,flexShrink:0,background:"#0a1120ee",backdropFilter:"blur(10px)",zIndex:20,flexWrap:"wrap"}}>
        <button onClick={onBack} style={{background:"transparent",border:"1px solid rgba(103,215,255,0.25)",color:"#67d7ff",padding:"5px 14px",borderRadius:7,cursor:"pointer",fontSize:11,letterSpacing:"0.12em",textTransform:"uppercase",flexShrink:0}}>← Zurück</button>
        <div>
          <div style={{fontSize:9,fontWeight:700,letterSpacing:"0.14em",color:"#a78bfa",textTransform:"uppercase"}}>mySkillbox</div>
          <div style={{fontSize:14,fontWeight:300}}>Venn · 3D</div>
        </div>
        {/* Zone legend */}
        <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap",marginLeft:4}}>
          {Object.entries(GROUP_META).map(([k,v])=>(
            <div key={k} style={{display:"flex",alignItems:"center",gap:4}}>
              <div style={{width:8,height:8,borderRadius:"50%",background:v.color,boxShadow:"0 0 6px "+v.color+"88"}}/>
              <span style={{fontSize:9,color:"#64748b"}}>{v.label}</span>
            </div>
          ))}
          {[["Schnittmengen","#34d399"],["Zentrum","#f8fafc"],["Rahmen (Ring)","#fbbf24"]].map(([l,c])=>(
            <div key={l} style={{display:"flex",alignItems:"center",gap:4}}>
              <div style={{width:8,height:8,borderRadius:"50%",background:c,boxShadow:"0 0 5px "+c+"77"}}/>
              <span style={{fontSize:9,color:"#64748b"}}>{l}</span>
            </div>
          ))}
        </div>
        <div style={{flex:1}}/>
        {/* Link legend */}
        <div style={{display:"flex",gap:8,borderRight:"1px solid #1e293b",paddingRight:12,alignItems:"center"}}>
          {typeConf.map(({key,label,color,dash})=>(
            <div key={key} style={{display:"flex",alignItems:"center",gap:4}}>
              <svg width="16" height="4"><line x1="0" y1="2" x2="16" y2="2" stroke={color} strokeWidth="1.5" strokeDasharray={dash||undefined}/></svg>
              <span style={{fontSize:9,color:"#64748b"}}>{label}</span>
            </div>
          ))}
        </div>
        {/* Search */}
        <div style={{position:"relative",flexShrink:0}}>
          <div style={{display:"flex",alignItems:"center",background:"#1e293b",border:"1px solid "+(searchQ?"#a78bfa88":"#334155"),borderRadius:10,overflow:"hidden",transition:"border-color .2s"}}>
            <span style={{padding:"0 8px",color:"#64748b",fontSize:13}}>⌕</span>
            <input ref={searchInputRef} value={search}
              onChange={e=>{setSearch(e.target.value);setSelected(null);}}
              onFocus={()=>setSearchFocus(true)}
              onBlur={()=>setTimeout(()=>setSearchFocus(false),160)}
              onKeyDown={e=>{if(e.key==="Escape"){setSearch("");searchInputRef.current&&searchInputRef.current.blur();}}}
              placeholder="Instrument suchen…"
              style={{background:"transparent",border:"none",outline:"none",padding:"6px 0",color:"#e2e8f0",fontSize:12,width:170,fontFamily:"inherit"}}
            />
            {search&&<button onClick={()=>{setSearch("");searchInputRef.current&&searchInputRef.current.focus();}} style={{background:"none",border:"none",padding:"0 8px",color:"#64748b",cursor:"pointer",fontSize:15,lineHeight:1}}>×</button>}
          </div>
          {searchQ&&searchFocus&&searchHits.length>0&&(
            <div style={{position:"absolute",top:"calc(100% + 6px)",left:0,minWidth:255,background:"#1e293b",border:"1px solid #334155",borderRadius:10,overflow:"hidden",zIndex:100,boxShadow:"0 8px 32px #00000099"}}>
              <div style={{padding:"5px 12px 4px",fontSize:8,color:"#64748b",letterSpacing:"0.1em",textTransform:"uppercase",borderBottom:"1px solid #334155"}}>{searchHits.length} Treffer</div>
              {searchHits.map(inst=>(
                <div key={inst.id} onMouseDown={()=>{setSelected(inst.id);setSearch("");}}
                  style={{display:"flex",alignItems:"center",gap:8,padding:"7px 12px",cursor:"pointer",borderBottom:"1px solid #0f172a"}}
                  onMouseEnter={e=>e.currentTarget.style.background="#334155"}
                  onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                  <div style={{width:8,height:8,borderRadius:inst.cat==="RAHMEN"?"2px":"50%",background:getColor(inst).css,flexShrink:0}}/>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:11,color:"#f1f5f9",fontWeight:500,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{inst.name}</div>
                    <div style={{fontSize:9,color:"#64748b",marginTop:1}}>{inst.cat}{inst.cat==="RAHMEN"?" · ◈":""}</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      <div style={{flex:1,display:"flex",overflow:"hidden",position:"relative"}}>
        <canvas ref={canvasRef} style={{flex:1,display:"block",width:"100%",height:"100%"}}/>

        {/* Label overlay container */}
        <div ref={labelContainerRef} style={{position:"absolute",inset:0,pointerEvents:"none",overflow:"hidden"}}/>

        {/* Hover tooltip */}
        {hovInst&&!selected&&(
          <div style={{position:"fixed",left:Math.min(((tooltip&&tooltip.x)||0)+16,window.innerWidth-240),top:((tooltip&&tooltip.y)||0)-24,background:"#1e293bee",border:"1px solid #334155",borderRadius:9,padding:"7px 12px",pointerEvents:"none",zIndex:50,backdropFilter:"blur(10px)"}}>
            <div style={{fontSize:12,fontWeight:600,color:"#f1f5f9"}}>{hovInst.name}</div>
            <div style={{fontSize:9,color:getColor(hovInst).css,marginTop:3,display:"flex",alignItems:"center",gap:5}}>
              <div style={{width:5,height:5,borderRadius:"50%",background:getColor(hovInst).css}}/>
              {hovInst.cat==="RAHMEN"?"Rahmeninstrument":hovInst.cat} · S.{hovInst.id}
            </div>
          </div>
        )}

        {/* Detail panel */}
        {selected&&selInst&&panelLinks&&(
          <div style={{width:285,background:"#0f172a",borderLeft:"1px solid #1e293b",display:"flex",flexDirection:"column",overflow:"hidden",flexShrink:0,animation:"si .18s ease",zIndex:10}}>
            <div style={{padding:"16px",borderBottom:"1px solid #1e293b",background:getColor(selInst).css+"14"}}>
              {selInst.cat==="RAHMEN"&&(
                <div style={{display:"inline-block",background:"#fbbf2414",border:"1px solid #fbbf2444",borderRadius:5,padding:"2px 8px",fontSize:8,color:"#fcd34d",letterSpacing:"0.07em",marginBottom:8}}>
                  ◈ RAHMENINSTRUMENT — Orbit
                </div>
              )}
              <div style={{fontSize:8,color:getColor(selInst).css,textTransform:"uppercase",letterSpacing:"0.1em",fontWeight:600,marginBottom:4}}>
                {selInst.cat==="RAHMEN"?"Rahmen":selInst.cat} · S.{selInst.id}
              </div>
              <div style={{fontSize:14,fontWeight:600,lineHeight:1.35,color:"#f8fafc"}}>{selInst.name}</div>
              <div style={{marginTop:10,display:"flex",gap:12}}>
                {typeConf.map(({key,label,color})=>(
                  <div key={key}>
                    <div style={{fontSize:17,fontWeight:700,color,lineHeight:1}}>{panelLinks[key].length}</div>
                    <div style={{fontSize:8,color:"#475569",marginTop:2}}>{label}</div>
                  </div>
                ))}
              </div>
            </div>

            <div style={{flex:1,overflowY:"auto",padding:"12px"}}>
              {typeConf.map(({key,label,color,dash})=>panelLinks[key].length>0&&(
                <div key={key} style={{marginBottom:14}}>
                  <div style={{fontSize:8,color:color+"bb",textTransform:"uppercase",letterSpacing:"0.08em",fontWeight:600,marginBottom:7,display:"flex",alignItems:"center",gap:5}}>
                    <svg width="14" height="4"><line x1="0" y1="2" x2="14" y2="2" stroke={color} strokeWidth="1.5" strokeDasharray={dash||undefined}/></svg>
                    {label} ({panelLinks[key].length})
                  </div>
                  {panelLinks[key].map(({inst,dir})=>(
                    <div key={inst.id} onClick={()=>setSelected(inst.id)}
                      style={{display:"flex",alignItems:"center",gap:8,padding:"6px 9px",borderRadius:8,marginBottom:3,cursor:"pointer",background:"#1e293b",border:"1px solid #334155",transition:"background .14s"}}
                      onMouseEnter={e=>e.currentTarget.style.background="#334155"}
                      onMouseLeave={e=>e.currentTarget.style.background="#1e293b"}>
                      <div style={{width:7,height:7,borderRadius:"50%",background:getColor(inst).css,flexShrink:0}}/>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{fontSize:11,color:"#f1f5f9",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{inst.name}</div>
                        <div style={{fontSize:9,color:"#475569"}}>S.{inst.id} · {inst.cat}{RAHMEN_IDS.has(inst.id)?" · ◈":""}</div>
                      </div>
                      <div style={{fontSize:9,color:"#475569"}}>{dir}</div>
                    </div>
                  ))}
                </div>
              ))}
              {typeConf.every(({key})=>panelLinks[key].length===0)&&(
                <div style={{color:"#475569",fontSize:12,textAlign:"center",marginTop:24}}>Keine Verbindungen</div>
              )}
            </div>
            <div style={{padding:"10px 12px",borderTop:"1px solid #1e293b"}}>
              <button onClick={()=>setSelected(null)} style={{width:"100%",padding:"7px",borderRadius:8,border:"1px solid #334155",background:"transparent",color:"#64748b",fontSize:11,cursor:"pointer"}}>✕ Schliessen</button>
            </div>
          </div>
        )}

        {!selected&&!searchQ&&(
          <div style={{position:"absolute",bottom:12,left:"50%",transform:"translateX(-50%)",fontSize:9,color:"#334155",pointerEvents:"none",textAlign:"center"}}>
            Ziehen = drehen · Klick = Instrument wählen · Scrollen = zoomen
          </div>
        )}
      </div>

      <div style={{padding:"4px 16px",borderTop:"1px solid #1e293b",display:"flex",gap:14,flexShrink:0,background:"#0a1120",alignItems:"center"}}>
        <span style={{fontSize:9,color:"#334155"}}>{INSTRUMENTS.length} Instrumente</span>
        <span style={{fontSize:9,color:"#93c5fd33"}}>{EXPLICIT.length} explizit</span>
        <span style={{fontSize:9,color:"#c4b5fd33"}}>{IMPLICIT.length} implizit</span>
        <span style={{fontSize:9,color:"#fcd34d33"}}>{RAHMEN_LINKS.length} Rahmen</span>
        {selected&&<span style={{fontSize:9,color:"#a78bfa"}}>▸ {selInst&&selInst.name?selInst.name:""}</span>}
        {searchQ&&<span style={{fontSize:9,color:"#a78bfa"}}>⌕ «{searchQ}»</span>}
      </div>
    </div>
  );
}

function Card({ part, delay, onSelect }) {
  const [hovered, setHovered] = useState(false);
  return (
    <div
      onClick={function() { if (!part.subparts) { onSelect(part.id); } }}
      onMouseEnter={function() { setHovered(true); }}
      onMouseLeave={function() { setHovered(false); }}
      style={{
        flex: "1 1 260px", maxWidth: 320,
        background: hovered ? "rgba(255,255,255,0.038)" : "rgba(255,255,255,0.018)",
        border: "1px solid " + (hovered ? part.color + "55" : "rgba(103,215,255,0.12)"),
        borderRadius: 16, padding: "28px 22px 24px",
        cursor: "pointer", position: "relative", overflow: "hidden",
        animation: "cardReveal 0.7s cubic-bezier(0.16,1,0.3,1) " + delay + "s both",
        transform: hovered ? "translateY(-8px)" : "translateY(0)",
        boxShadow: hovered ? "0 28px 64px " + part.glow : "none",
        transition: "transform 0.28s ease, box-shadow 0.28s ease, border-color 0.28s ease, background 0.28s ease",
      }}
    >
      <div style={{ position: "absolute", top: 0, left: 0, width: 30, height: 30,
        borderTop: "1.5px solid " + part.color, borderLeft: "1.5px solid " + part.color,
        borderRadius: "16px 0 0 0", opacity: hovered ? 0.9 : 0.5, transition: "opacity 0.28s ease", pointerEvents: "none" }}/>
      <div style={{ position: "absolute", bottom: 0, right: 0, width: 30, height: 30,
        borderBottom: "1.5px solid " + part.color, borderRight: "1.5px solid " + part.color,
        borderRadius: "0 0 16px 0", opacity: hovered ? 0.5 : 0.2, transition: "opacity 0.28s ease", pointerEvents: "none" }}/>
      <div style={{ fontSize: "clamp(9px, 0.9vw, 11px)", color: part.color,
        letterSpacing: "0.3em", textTransform: "uppercase", fontWeight: 600, marginBottom: 14, opacity: 0.75 }}>
        {part.num}
      </div>
      <div style={{ fontSize: "clamp(22px, 3vw, 30px)", fontFamily: "'Audiowide', monospace",
        color: "#f7fbff", marginBottom: 7, lineHeight: 1.15 }}>
        {part.title}
      </div>
      <div style={{ fontSize: "clamp(9px, 0.95vw, 11px)", color: part.color,
        letterSpacing: "0.12em", textTransform: "uppercase", marginBottom: 18, fontWeight: 500, opacity: 0.8 }}>
        {part.sub}
      </div>
      <p style={{ color: "rgba(247,251,255,0.42)", fontSize: "clamp(11px, 1.05vw, 13px)", lineHeight: 1.72, margin: 0 }}>
        {part.desc}
      </p>
      {part.subparts
        ? (
          <div style={{ marginTop: 22, display: "flex", flexDirection: "column", gap: 8 }}>
            {part.subparts.map(function(sp) {
              return (
                <div key={sp.id}
                  onClick={function(e) { e.stopPropagation(); onSelect(sp.id); }}
                  onMouseEnter={function(e) {
                    e.currentTarget.style.background = part.color + "18";
                    e.currentTarget.style.borderColor = part.color + "80";
                  }}
                  onMouseLeave={function(e) {
                    e.currentTarget.style.background = "transparent";
                    e.currentTarget.style.borderColor = part.color + "40";
                  }}
                  style={{
                    display: "flex", alignItems: "center", justifyContent: "space-between",
                    padding: "8px 14px",
                    border: "1px solid " + part.color + "40",
                    borderRadius: 7, cursor: "pointer",
                    color: part.color,
                    fontSize: "clamp(9px, 0.88vw, 11px)",
                    letterSpacing: "0.1em", textTransform: "uppercase", fontWeight: 500,
                    transition: "background 0.18s ease, border-color 0.18s ease",
                  }}>
                  {sp.label}
                  <span style={{ fontSize: 13, marginLeft: 4 }}>›</span>
                </div>
              );
            })}
          </div>
        )
        : (
          <div style={{ marginTop: 22, display: "flex", alignItems: "center", gap: 6,
            color: part.color, fontSize: "clamp(9px, 0.95vw, 11px)", letterSpacing: "0.18em",
            textTransform: "uppercase", fontWeight: 600, opacity: hovered ? 1 : 0.65,
            transition: "opacity 0.28s ease" }}>
            Öffnen <span style={{ fontSize: 13, marginTop: 1 }}>›</span>
          </div>
        )
      }
    </div>
  );
}

function ComingSoon({ part, onBack }) {
  return (
    <div style={{ minHeight: "100vh", background: "#05070b", display: "flex",
      flexDirection: "column", alignItems: "center", justifyContent: "center",
      fontFamily: "'Exo 2', sans-serif", gap: 14, position: "relative" }}>
      <div style={{ position: "fixed", inset: 0, pointerEvents: "none",
        background: "radial-gradient(ellipse at 50% 50%, " + part.glow.replace("0.22","0.08") + " 0%, transparent 60%)" }}/>
      <div style={{ fontSize: "clamp(10px, 1.3vw, 12px)", color: part.color,
        letterSpacing: "0.35em", textTransform: "uppercase", fontWeight: 600, opacity: 0.7,
        animation: "fadeSlideDown 0.5s ease-out both" }}>
        {part.num}
      </div>
      <div style={{ fontSize: "clamp(30px, 6vw, 56px)", fontFamily: "'Audiowide', monospace",
        color: "#f7fbff", textAlign: "center", textShadow: "0 0 40px " + part.glow,
        animation: "fadeSlideDown 0.5s ease-out 0.1s both" }}>
        {part.title}
      </div>
      <div style={{ fontSize: "clamp(10px, 1.2vw, 13px)", color: "rgba(255,255,255,0.28)",
        letterSpacing: "0.15em", textTransform: "uppercase", marginBottom: 20,
        animation: "fadeSlideDown 0.5s ease-out 0.2s both" }}>
        {part.sub} — wird als nächstes integriert
      </div>
      <button onClick={onBack}
        style={{ background: "transparent", border: "1px solid rgba(103,215,255,0.25)",
          color: "#67d7ff", padding: "11px 30px", borderRadius: 9, cursor: "pointer",
          fontFamily: "'Exo 2', sans-serif", fontSize: 12, letterSpacing: "0.16em",
          textTransform: "uppercase", transition: "border-color 0.2s, background 0.2s",
          animation: "fadeSlideDown 0.5s ease-out 0.3s both" }}
        onMouseEnter={function(e) { e.currentTarget.style.borderColor = "#67d7ff"; e.currentTarget.style.background = "rgba(103,215,255,0.06)"; }}
        onMouseLeave={function(e) { e.currentTarget.style.borderColor = "rgba(103,215,255,0.25)"; e.currentTarget.style.background = "transparent"; }}>
        ← Zurück
      </button>
    </div>
  );
}

function LionMorph(props) {
  var mirrored = props.mirrored || false;
  return React.createElement("img", {
    src: "data:image/gif;base64," + LION_B64,
    alt: "Peino",
    style: {
      width: "100%", maxWidth: 480, height: "auto",
      display: "block", mixBlendMode: "screen",
      transform: mirrored ? "scaleX(-1)" : "none",
    }
  });
}


